const invoices = $input.all().map(i => i.json);
const config = $('Configure Settings').first().json;
const today = new Date();

let totalPaid = 0;
let totalUnpaid = 0;
let totalOverdue = 0;
const overdueList = [];
const unpaidList = [];

for (const inv of invoices) {
  const amount = parseFloat(inv['Amount'] || inv['amount'] || 0);
  const status = (inv['Status'] || inv['status'] || '').toLowerCase();
  const dueDate = new Date(inv['Due Date'] || inv['due_date'] || '');
  const clientName = inv['Client Name'] || inv['client_name'] || 'Unknown';
  const invoiceId = inv['Invoice ID'] || inv['invoice_id'] || 'N/A';

  if (status === 'paid') {
    totalPaid += amount;
  } else {
    totalUnpaid += amount;
    unpaidList.push({ invoiceId, clientName, amount, dueDate: dueDate.toISOString().split('T')[0] });

    if (dueDate < today) {
      totalOverdue += amount;
      const daysOverdue = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
      overdueList.push({ invoiceId, clientName, amount, dueDate: dueDate.toISOString().split('T')[0], daysOverdue });
    }
  }
}

const overdueRows = overdueList.map(o =>
  `<tr><td>${o.invoiceId}</td><td>${o.clientName}</td><td>$${o.amount.toFixed(2)}</td><td>${o.dueDate}</td><td style="color:red;font-weight:bold;">${o.daysOverdue} days</td></tr>`
).join('');

const unpaidRows = unpaidList.map(u =>
  `<tr><td>${u.invoiceId}</td><td>${u.clientName}</td><td>$${u.amount.toFixed(2)}</td><td>${u.dueDate}</td></tr>`
).join('');

const emailHtml = `
<h2>Weekly Invoice Summary - ${config.businessName}</h2>
<p>Report generated: ${today.toISOString().split('T')[0]}</p>
<table style="border-collapse:collapse;width:100%;">
  <tr style="background:#f0f0f0;"><td style="padding:8px;"><strong>Total Paid</strong></td><td style="padding:8px;">$${totalPaid.toFixed(2)}</td></tr>
  <tr><td style="padding:8px;"><strong>Total Unpaid</strong></td><td style="padding:8px;">$${totalUnpaid.toFixed(2)}</td></tr>
  <tr style="background:#fff0f0;"><td style="padding:8px;"><strong>Total Overdue</strong></td><td style="padding:8px;color:red;font-weight:bold;">$${totalOverdue.toFixed(2)}</td></tr>
</table>
${overdueList.length > 0 ? `
<h3>Overdue Invoices (${overdueList.length})</h3>
<table style="border-collapse:collapse;width:100%;">
  <tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">ID</th><th style="padding:8px;text-align:left;">Client</th><th style="padding:8px;text-align:left;">Amount</th><th style="padding:8px;text-align:left;">Due Date</th><th style="padding:8px;text-align:left;">Overdue</th></tr>
  ${overdueRows}
</table>` : '<p>No overdue invoices this week.</p>'}
${unpaidList.length > 0 ? `
<h3>All Unpaid Invoices (${unpaidList.length})</h3>
<table style="border-collapse:collapse;width:100%;">
  <tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">ID</th><th style="padding:8px;text-align:left;">Client</th><th style="padding:8px;text-align:left;">Amount</th><th style="padding:8px;text-align:left;">Due Date</th></tr>
  ${unpaidRows}
</table>` : ''}
`;

const slackOverdueText = overdueList.map(o =>
  `- *${o.invoiceId}* | ${o.clientName} | $${o.amount.toFixed(2)} | Due: ${o.dueDate} (*${o.daysOverdue} days overdue*)`
).join('\n');

return [{
  json: {
    ...config,
    emailHtml,
    totalPaid,
    totalUnpaid,
    totalOverdue,
    totalPaidFormatted: totalPaid.toFixed(2),
    totalUnpaidFormatted: totalUnpaid.toFixed(2),
    totalOverdueFormatted: totalOverdue.toFixed(2),
    overdueCount: overdueList.length,
    hasOverdue: overdueList.length > 0,
    slackOverdueText,
    reportDate: today.toISOString().split('T')[0]
  }
}];
